def solve():
    input_str = """9 9 9 9 1
9 9 9 9 0
9 2 2 9 0
9 9 9 9 0
9 9 9 9 0"""

    grid = [[int(n) for n in line.split()] for line in input_str.split('\n')]

    num_rows = len(grid)
    num_cols = len(grid[0])

    def is_control_line(line):
        return all(x in [0, 1] for x in line)

    orientation = None
    data_grid = []
    control_grid = []

    last_row = grid[-1]
    if is_control_line(last_row):
        orientation = 'vertical'
        num_control_rows = 0
        for r in range(num_rows - 1, -1, -1):
            if is_control_line(grid[r]):
                num_control_rows += 1
            else:
                break
        data_grid = grid[:-num_control_rows]
        control_grid = grid[-num_control_rows:]
    else:
        last_col = [grid[r][-1] for r in range(num_rows)]
        if is_control_line(last_col):
            orientation = 'horizontal'
            num_control_cols = 0
            for c in range(num_cols - 1, -1, -1):
                col = [grid[r][c] for r in range(num_rows)]
                if is_control_line(col):
                    num_control_cols += 1
                else:
                    break
            data_grid = [row[:-num_control_cols] for row in grid]
            control_grid = [row[-num_control_cols:] for row in grid]

    if not orientation:
        # Should not happen based on problem description
        return None

    n_markers = 0
    for row in control_grid:
        n_markers += row.count(1)

    repetitions = n_markers + 1

    output_grid = []
    if orientation == 'vertical':
        data_width = len(data_grid[0])
        separator = [0] * data_width
        for i in range(repetitions):
            output_grid.extend(data_grid)
            if i < repetitions - 1:
                output_grid.append(separator)
    elif orientation == 'horizontal':
        data_height = len(data_grid)
        for r in range(data_height):
            new_row = []
            for i in range(repetitions):
                new_row.extend(data_grid[r])
                if i < repetitions - 1:
                    new_row.append(0)
            output_grid.append(new_row)

    output_str_rows = [" ".join(map(str, row)) for row in output_grid]
    result_grid = "\n".join(output_str_rows)

    rule = "A control section (rows or columns containing only 0s and 1s) determines how the data section is repeated. The number of 1s (N) in the control section dictates N+1 repetitions. Repetition is horizontal (separated by a zero-column) for control columns, and vertical (separated by a zero-row) for control rows."

    import json
    result = {"rule": rule, "grid": result_grid}
    print(json.dumps(result))

solve()
